   117Ôćĺ			// Render buffered text with markdown
   118Ôćĺ			text := r.textBuffer.String()
   119Ôćĺ			if text != "" {
   120Ôćĺ				rendered := r.markdownRenderer.Render(text)
   121Ôćĺ				fmt.Print(rendered)
   122Ôćĺ			}
   123Ôćĺ		} else if r.InToolUseBlock && event.Event.Index == r.CurrentBlockIndex {
