   125Ôćĺ			var input map[string]interface{}
   126Ôćĺ			toolInputStr := r.toolInput.String()
   127Ôćĺ			if err := json.Unmarshal([]byte(toolInputStr), &input); err == nil {
   128Ôćĺ				tools.RenderToolHeader(r.toolName, input)
   129Ôćĺ			} else {
