   138Ôćĺ		// Note: Don't reset InTextBlock/InToolUseBlock here - they persist
   139Ôćĺ		// until after the assistant event is processed to prevent duplicate rendering
   140Ôćĺ		r.CurrentBlockIndex = -1
   141Ôćĺ	}
   142Ôćĺ}
