    49Ôćĺ			args = path
    50Ôćĺ			filePath = path
    51Ôćĺ		}
    52Ôćĺ	case "Glob":
    53Ôćĺ		if pattern, ok := input["pattern"].(string); ok {
    54Ôćĺ			args = pattern
    55Ôćĺ		}
    56Ôćĺ	case "Grep":
    57Ôćĺ		if pattern, ok := input["pattern"].(string); ok {
    58Ôćĺ			args = pattern
    59Ôćĺ		}
    60Ôćĺ	case "Task":
    61Ôćĺ		if desc, ok := input["description"].(string); ok {
    62Ôćĺ			args = desc
    63Ôćĺ		}
    64Ôćĺ	default:
