    67Ôćĺ			if data, err := json.Marshal(input); err == nil {
    68Ôćĺ				args = string(data)
    69Ôćĺ				if len(args) > 100 {
    70Ôćĺ					args = args[:100] + "..."
    71Ôćĺ				}
    72Ôćĺ			}
    73Ôćĺ		}
    74Ôćĺ	}
